import React, { useState } from "react";
import axios from "axios";
import "./App.css";

function App() {
  const [jsonPath, setJsonPath] = useState("");
  const [jsonPathResult, setJsonPathResult] = useState(null);
  const [imagePath, setImagePath] = useState("");
  const [imageUrl, setImageUrl] = useState("");

  const backendUrl = "http://localhost:8000"; // Backend base URL

  const handleJSONPathQuery = async () => {
    if (!jsonPath) {
      alert("Please enter a JSONPath query.");
      return;
    }

    try {
      const response = await axios.get(`${backendUrl}/query`, {
        params: { path: jsonPath },
      });
      setJsonPathResult(response.data.result);
    } catch (error) {
      console.error("Error querying JSONPath:", error);
      alert("Failed to query JSONPath.");
    }
  };

  const handleFetchImage = async () => {
    if (!imagePath) {
      alert("Please enter an image path.");
      return;
    }

    try {
      const response = await axios.get(`${backendUrl}/fetch-image`, {
        params: { path: imagePath },
        responseType: "arraybuffer",
      });

      const imageBlob = new Blob([response.data], { type: response.headers["content-type"] });
      setImageUrl(URL.createObjectURL(imageBlob));
    } catch (error) {
      console.error("Error fetching image:", error);
      alert("Failed to fetch the image.");
    }
  };

  return (
    <div className="App">
      <header>
        <h1>EXIF STRIPPER</h1>
      </header>
      <div className="container">

        <hr />

        {/* Image Fetch Section */}
        <section>
          <h2>Fetch Image</h2>
          <div className="form-group">
            <label>Enter Image Path:</label>
            <input
              type="text"
              value={imagePath}
              onChange={(e) => setImagePath(e.target.value)}
              placeholder="200/300"
            />
            <button onClick={handleFetchImage}>Fetch</button>
          </div>
          {imageUrl && (
            <div className="result">
              <img src={imageUrl} alt="Fetched" style={{ maxWidth: "100%", height: "auto" }} />
            </div>
          )}
        </section>

        {imageUrl && (
          <section>
            <h2>EXIF Data</h2>
            <button></button>
          </section>
        )
        }

        {/* JSONPath Query Section */}
        <section>
          <h2>JSONPath Query</h2>
          <div className="form-group">
            <label>Enter JSONPath:</label>
            <input
              type="text"
              value={jsonPath}
              onChange={(e) => setJsonPath(e.target.value)}
              placeholder="$..name"
            />
            <button onClick={handleJSONPathQuery}>Submit</button>
          </div>
          {jsonPathResult && (
            <div className="result">
              <strong>Result:</strong>
              <pre>{JSON.stringify(jsonPathResult, null, 2)}</pre>
            </div>
          )}
        </section>
      </div>
    </div>
  );
}

export default App;
